class ParseError(Exception):
    def __init__(self, message: str, line: int, column: int, context: str = ''):
        self.line = line
        self.column = column
        self.context = context
        super().__init__(f'{message} at line {line}, column {column}')

    def __str__(self):
        msg = super().__str__()
        if self.context:
            msg += f'\n  {self.context}\n  {" " * (self.column - 1)}^'
        return msg
